INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190805, 1000001, 2, 62, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1, "2025/01/31 12:00:00", "カリン", -416.5, "2030/01/01 14:59:59", 0.0, 3.414, 1, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190805, 1000002, 2, 62, "ミッションをクリアして、\n報酬をゲットしましょう！", 1, "2025/01/31 12:00:00", "カリン", -416.5, "2030/01/01 14:59:59", 0.0, 3.099, 2, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190805, 1000003, 2, 63, "受け取ることができる\n報酬があるようです\n確認してみてください", 1, "2025/01/31 12:00:00", "カリン", -416.5, "2030/01/01 14:59:59", 0.0, 2.801, 3, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190805, 1000004, 2, 63, "報酬がもらえますよ！\nチェックしてみてください", 1, "2025/01/31 12:00:00", "カリン", -416.5, "2030/01/01 14:59:59", 0.0, 0.0, 4, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190805, 1000005, 1, 64, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1, "2025/01/31 12:00:00", "カリン", -363.0, "2030/01/01 14:59:59", 0.0, 2.12, 5, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190805, 1000006, 2, 64, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1, "2025/01/31 12:00:00", "カリン", -363.0, "2030/01/01 14:59:59", 0.0, 1.68, 6, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190805, 1000007, 1, 64, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1, "2025/01/31 12:00:00", "カリン", -363.0, "2030/01/01 14:59:59", 0.0, 2.33, 7, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (133701, 1020101, 7, 61, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 10201, "2025/01/31 12:00:00", "ラビリスタ", -285.0, "2030/01/01 14:59:59", -6.0, 5.18, 101, 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (133901, 1020102, 2, 61, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 10201, "2025/01/31 12:00:00", "クリスティーナ", -285.0, "2030/01/01 14:59:59", -2.0, 8.77, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (133801, 1020103, 1, 61, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 10201, "2025/01/31 12:00:00", "ネネカ", -285.0, "2030/01/01 14:59:59", 0.0, 15.5, 301, 6);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (134301, 1020201, 5, 61, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 10202, "2025/02/28 12:00:00", "ランファ", -285.0, "2030/01/01 14:59:59", 0.0, 9.061, 101, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (134401, 1020202, 2, 61, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 10202, "2025/02/28 12:00:00", "チカ", -285.0, "2030/01/01 14:59:59", 0.0, 7.699, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (134601, 1020301, 2, 61, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 10203, "2025/03/31 12:00:00", "アオイ", -285.0, "2030/01/01 14:59:59", 0.0, 8.595, 101, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (134501, 1020302, 2, 61, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 10203, "2025/03/31 12:00:00", "クローチェ", -285.0, "2030/01/01 14:59:59", 0.0, 7.758, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (132302, 1020401, 6, 61, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 10204, "2025/04/30 12:00:00", "ルイズマリー", -285.0, "2030/01/01 14:59:59", 0.0, 7.0, 101, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (132402, 1020402, 2, 61, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 10204, "2025/04/30 12:00:00", "イロハ", -285.0, "2030/01/01 14:59:59", 0.0, 7.904, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (132502, 1020403, 2, 61, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 10204, "2025/04/30 12:00:00", "ソノ", -285.0, "2030/01/01 14:59:59", 0.0, 8.487, 301, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (134901, 1020502, 2, 61, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 10205, "2025/05/31 12:00:00", "カノン", -285.0, "2030/01/01 14:59:59", 0.0, 8.763, 101, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (134801, 1020503, 3, 61, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 10205, "2025/05/31 12:00:00", "ツムギ", -285.0, "2030/01/01 14:59:59", 0.0, 6.417, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (135001, 1020601, 7, 61, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 10206, "2025/06/30 12:00:00", "エリス", -285.0, "2030/01/01 14:59:59", 0.0, 10.335, 101, 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (135101, 1020602, 4, 61, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 10206, "2025/06/30 12:00:00", "シェフィ", -285.0, "2030/01/01 14:59:59", 0.0, 6.281, 201, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (135201, 1020603, 2, 61, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 10206, "2025/06/30 12:00:00", "プレシア", -285.0, "2030/01/01 14:59:59", 0.0, 12.244, 301, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (135301, 1020701, 8, 61, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 10207, "2025/07/31 12:00:00", "クリア", -285.0, "2030/01/01 14:59:59", 0.0, 6.339, 101, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (135401, 1020702, 9, 61, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 10207, "2025/07/31 12:00:00", "アネモネ", -285.0, "2030/01/01 14:59:59", 0.0, 8.184, 201, 7);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (129101, 1020801, 2, 61, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 10208, "2025/08/31 12:00:00", "アイラ", -285.0, "2030/01/01 14:59:59", 0.0, 3.906, 101, 9);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (129201, 1020802, 2, 61, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 10208, "2025/08/31 12:00:00", "シナツ", -285.0, "2030/01/01 14:59:59", 0.0, 14.465, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (100101, 1020803, 3, 61, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 10208, "2025/08/31 12:00:00", "ヒヨリ", -285.0, "2030/01/01 14:59:59", 0.0, 8.662, 301, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (100301, 1020804, 3, 61, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 10208, "2025/08/31 12:00:00", "レイ", -285.0, "2030/01/01 14:59:59", 0.0, 10.915, 401, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (135802, 1020901, 7, 61, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 10209, "2025/09/30 12:00:00", "ユキノ", -285.0, "2030/01/01 14:59:59", 0.0, 6.042, 101, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (135903, 1020902, 1, 61, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 10209, "2025/09/30 12:00:00", "サツキ", -285.0, "2030/01/01 14:59:59", 0.0, 9.402, 201, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (136902, 1020903, 1, 61, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 10209, "2025/09/30 12:00:00", "ルルィ", -285.0, "2030/01/01 14:59:59", 0.0, 8.16, 301, 8);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (137401, 1021001, 2, 61, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 10210, "2025/10/31 12:00:00", "カスミ", -285.0, "2030/01/01 14:59:59", 0.0, 5.0, 101, 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (136001, 1021002, 1, 61, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 10210, "2025/10/31 12:00:00", "アラクネ", -285.0, "2030/01/01 14:59:59", 0.0, 8.12, 201, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (136202, 1021003, 2, 61, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 10210, "2025/10/31 12:00:00", "ナーナ", -285.0, "2030/01/01 14:59:59", 0.0, 6.386, 301, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (136402, 1021101, 4, 61, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 10211, "2025/11/30 12:00:00", "ユイ", -285.0, "2030/01/01 14:59:59", 0.0, 7.438, 101, 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (136302, 1021102, 5, 61, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 10211, "2025/11/30 12:00:00", "ミソラ", -285.0, "2030/01/01 14:59:59", 0.0, 8.35, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (136501, 1021201, 2, 61, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 10212, "2025/12/31 12:00:00", "シズル", -285.0, "2030/01/01 14:59:59", 0.0, 5.0, 101, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (137902, 1021202, 2, 61, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 10212, "2025/12/31 12:00:00", "リノ", -285.0, "2030/01/01 14:59:59", 0.0, 5.25, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (106801, 1021203, 2, 61, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 10212, "2025/12/31 12:00:00", "ラビリスタ", -285.0, "2030/01/01 14:59:59", 0.0, 7.5, 301, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (126501, 1021301, 2, 61, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 10213, "2026/01/31 12:00:00", "ライラエル", -285.0, "2030/01/01 14:59:59", 0.0, 8.204, 101, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (129701, 1021302, 2, 61, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 10213, "2026/01/31 12:00:00", "ネフィ＝ネラ", -285.0, "2030/01/01 14:59:59", 0.0, 7.176, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (133101, 1021303, 5, 61, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 10213, "2026/01/31 12:00:00", "ヴァイオレット", -285.0, "2030/01/01 14:59:59", 0.0, 8.602, 301, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (138101, 1021304, 3, 61, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 10213, "2026/02/06 12:00:00", "ライラエル", -285.0, "2030/01/01 14:59:59", 0.0, 10.14, 102, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (138201, 1021305, 7, 61, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 10213, "2026/02/06 12:00:00", "ネフィ＝ネラ", -285.0, "2030/01/01 14:59:59", 0.0, 10.152, 202, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (138001, 1021306, 3, 61, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 10213, "2026/02/06 12:00:00", "ヴァイオレット", -285.0, "2030/01/01 14:59:59", 0.0, 9.688, 302, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (138301, 1021307, 1, 61, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 10213, "2026/02/12 12:00:00", "ペコリーヌ", -285.0, "2030/01/01 14:59:59", 0.0, 5.928, 401, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (138702, 1021401, 2, 61, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 10214, "2026/02/28 12:00:00", "ワカナ", -285.0, "2030/01/01 14:59:59", 0.0, 9.19, 101, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (138802, 1021402, 3, 61, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 10214, "2026/02/28 12:00:00", "シオリ", -285.0, "2030/01/01 14:59:59", 0.0, 8.724, 201, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (138902, 1021501, 1, 61, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 10215, "2026/03/31 12:00:00", "グレイス", -285.0, "2030/01/01 14:59:59", 0.0, 7.758, 101, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (139002, 1021502, 4, 61, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 10215, "2026/03/31 12:00:00", "キョウカ", -285.0, "2030/01/01 14:59:59", 0.0, 6.375, 201, 6);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (136902, 1021503, 1, 61, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 10215, "2026/03/31 12:00:00", "ルルィ", -285.0, "2030/01/01 14:59:59", 0.0, 6.173, 301, 6);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (139202, 1021601, 2, 61, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 10216, "2026/04/30 12:00:00", "ミホ", -285.0, "2030/01/01 14:59:59", 0.0, 4.202, 101, 6);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (139302, 1021602, 1, 61, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 10216, "2026/04/30 12:00:00", "マホ", -285.0, "2030/01/01 14:59:59", 0.0, 2.842, 201, 6);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (139402, 1021603, 1, 61, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 10216, "2026/04/30 12:00:00", "エリカ", -285.0, "2030/01/01 14:59:59", 0.0, 4.598, 301, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (125802, 1021701, 3, 61, "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", 10217, "2026/05/31 12:00:00", "リリ", -285.0, "2030/01/01 14:59:59", 0.0, 6.533, 101, 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (126102, 1021702, 3, 61, "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", 10217, "2026/05/31 12:00:00", "プレシア", -285.0, "2030/01/01 14:59:59", 0.0, 5.0, 301, 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (126002, 1021703, 4, 61, "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", 10217, "2026/05/31 12:00:00", "クリア", -285.0, "2030/01/01 14:59:59", 0.0, 5.214, 201, 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (139501, 1021704, 3, 61, "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", 10217, "2026/05/31 12:00:00", "リリ", -285.0, "2030/01/01 14:59:59", 0.0, 8.781, 102, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (139601, 1021705, 1, 61, "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", 10217, "2026/05/31 12:00:00", "クリア", -285.0, "2030/01/01 14:59:59", 0.0, 6.529, 202, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (139701, 1021706, 2, 61, "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", 10217, "2026/05/31 12:00:00", "プレシア", -285.0, "2030/01/01 14:59:59", 0.0, 3.195, 302, 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (139902, 1021801, 3, 61, "ダーリンと一緒に南の島で\nリゾート開発なんて夢みたい♪\nああ…幸せ、最高の夏だわ…\n触れたら爆発さえしなければ～…っ", 10218, "2026/06/30 12:00:00", "ルイズマリー", -285.0, "2030/01/01 14:59:59", 0.0, 12.43, 101, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (140001, 1021802, 3, 61, "青い空、白い雲…無人島リゾートで\n大儲けですわ～♪　こらこらそこ、\nイチャついてるんじゃないですのよ\n触れたらドカンですわよ、ドカン！", 10218, "2026/06/30 12:00:00", "クレジッタ", -285.0, "2030/01/01 14:59:59", 0.0, 6.35, 201, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190801, 2000001, 2, 62, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 2, "2026/04/10 12:00:00", "カリン", -416.5, "2030/01/01 14:59:59", 0.0, 3.414, 1, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190801, 2000002, 2, 62, "ミッションをクリアして、\n報酬をゲットしましょう！", 2, "2026/04/10 12:00:00", "カリン", -416.5, "2030/01/01 14:59:59", 0.0, 3.099, 2, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190801, 2000003, 2, 63, "受け取ることができる\n報酬があるようです\n確認してみてください", 2, "2026/04/10 12:00:00", "カリン", -416.5, "2030/01/01 14:59:59", 0.0, 2.801, 3, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190801, 2000004, 2, 63, "報酬がもらえますよ！\nチェックしてみてください", 2, "2026/04/10 12:00:00", "カリン", -416.5, "2030/01/01 14:59:59", 0.0, 0.0, 4, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190801, 2000005, 1, 64, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2, "2026/04/10 12:00:00", "カリン", -363.0, "2030/01/01 14:59:59", 0.0, 2.12, 5, 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190801, 2000006, 2, 64, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 2, "2026/04/10 12:00:00", "カリン", -363.0, "2030/01/01 14:59:59", 0.0, 1.68, 6, 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (190801, 2000007, 1, 64, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2, "2026/04/10 12:00:00", "カリン", -363.0, "2030/01/01 14:59:59", 0.0, 2.33, 7, 2);
